class Solution:
    def splitNum(self, num):
        digits = sorted(str(num))
        n = len(digits)
        best = None
        for mask in range(1, (1 << n) - 1):
            g1 = [digits[i] for i in range(n) if mask & (1 << i)]
            g2 = [digits[i] for i in range(n) if not (mask & (1 << i))]
            val = int(''.join(g1)) + int(''.join(g2))
            if best is None or val < best:
                best = val
        return best

