var splitNum = function(num) {
    const digits = String(num).split('').sort();
    let n1 = [], n2 = [];
    for (let i = 0; i < digits.length; i++) {
        if (i % 2 === 0) n1.push(digits[i]);
        else n2.push(digits[i]);
    }
    return parseInt(n1.join(''), 10) + parseInt(n2.join(''), 10);
};
